// 1. Obtener la métrica auditada y el contexto de la iteración actual
const auditMetrics = $('Update Metrics1').item?.json || {};
const contextItem = $('Query Loop').first().json || $node['Query Loop'].json;


// 2. Clonar el contexto para armar la salida
const outputItem = JSON.parse(JSON.stringify(contextItem));

// 3. Evaluar el estado unificado (status: true es OK, false es Error)
const isError = auditMetrics.status === false;

// Setear las banderas estandarizadas para el resto del flujo o para el HTML
outputItem._isError = isError;
outputItem._status = isError ? 'ERROR' : 'OK';
outputItem._errorMessage = auditMetrics.error_message || null;

// 4. Extraer los datos reales de la BD
let finalResults = [];

if (!isError) {
