// Classify SQL Execute error as TRANSIENT or FATAL.
const TRANSIENT_PATTERNS = [
  /timeout/i, /deadlock/i, /session.*kill/i, /killed.*session/i,
  /connection.*reset/i, /connection.*lost/i, /network.*error/i,
  /etimedout/i, /econnrefused/i, /econnreset/i
];
const FATAL_PATTERNS = [
  /login failed/i, /authentication/i, /password/i,
  /invalid object name/i, /invalid column name/i, /syntax error/i, /permission denied/i,
  /access.*denied/i, /must declare the scalar variable/i, /must be/i
];

const items = $input.all();

return items.map(item => {
  // 1. Detectar si hay error evaluando las banderas (SQL o n8n nativo)
  const isSqlError = item.json._isError === "true" || item.json._isError === true;
  const isN8nError = item.error && item.error.message;

  const hasError = !!(isSqlError || isN8nError);

  let errorType = null;
  let msg = null;

  // 2. Extraer el mensaje REAL y clasificar
  if (hasError) {
    // Si viene de SQL tomamos su mensaje, si no, tomamos el de n8n
    const rawErrorMsg = isSqlError ? item.json._errorMessage : item.error.message;
    msg = String(rawErrorMsg || "Error desconocido");

    // Clasificación por defecto (Asumimos TRANSIENT a menos que se demuestre lo contrario)
    errorType = 'TRANSIENT'; 

    if (FATAL_PATTERNS.some(re => re.test(msg))) {
      errorType = 'FATAL';
    } else if (TRANSIENT_PATTERNS.some(re => re.test(msg))) {
      errorType = 'TRANSIENT';
    } else if (item.json._errorType) {
      // Si la Regex no lo detectó, pero SQL nos sugirió un tipo, lo respetamos
      errorType = item.json._errorType;
    }
  }

  // 3. Limpiar las variables temporales del CATCH de SQL para no ensuciar el JSON final
  const cleanJson = { ...item.json };
  if (isSqlError) {
      delete cleanJson._isError;

  }

  // 4. Retornar la estructura final unificada
  return { 
    json: { 
      ...cleanJson, 
      has_error: hasError,
      error_type: errorType, 
      error_message: msg ? msg.slice(0, 1000) : null, 
      timeout: "180000" 
    } 
  };
});

const endTime = new Date().getTime();
const results = $input.all();
const firstInput = results[0]?.json || {};
// Capturar el error nativo de n8n si SQL Retry falló con "Continue On Fail"
const n8nNativeError = results[0]?.error; 

// 1. Tiempos y contextos
// Usamos .item en lugar de .first() para garantizar que obtenemos los datos de la iteración actual del Loop
const startTime = $('Audit Start').item?.json?.audit_startTime || $('Audit Start').first().json.audit_startTime;
const envData   = $('Credentials Loop').item?.json || {};
const queryData = $('Query Loop').item?.json || {};

// 2. Detectar error unificando ambas rutas
// Evaluamos si el clasificador dictaminó error, o si el nodo de reintento trajo un error nuevo
const rawError = firstInput.error || n8nNativeError || (firstInput.has_error ? firstInput.error_message : null);
const hasError = !!rawError || firstInput.has_error === true;

// 3. Extraer el mensaje de forma segura
let errorMessage = null;
if (hasError) {
  if (firstInput.error_message) {
    errorMessage = firstInput.error_message; // Prioridad al clasificador
  } else if (typeof rawError === 'string') {
    errorMessage = rawError; // Error directo en string
  } else if (rawError?.message) {
    errorMessage = rawError.message; // Error estructurado nativo de n8n o BD
  } else {
    errorMessage = JSON.stringify(rawError); // Último recurso
  }
}

// 4. Peso y conteo 
let payloadString, sizeInBytes, realResultsCount;
if (hasError) {
  payloadString = errorMessage || 'Error en ejecución de BD';
  sizeInBytes = Buffer.byteLength(payloadString, 'utf8');
  realResultsCount = 0;
} else {
  // Solo stringificamos el contenido "json" de los items para calcular el peso real
  payloadString = JSON.stringify(results.map(r => r.json));
  sizeInBytes = Buffer.byteLength(payloadString, 'utf8');
  realResultsCount = (results.length === 1 && Object.keys(firstInput).length === 0) ? 0 : results.length;
}

// 5. Fechas y timestamps
const now = new Date();
const arDateStr = now.toLocaleDateString("en-CA", { timeZone: "America/Argentina/Buenos_Aires" });
const arTimeStr = now.toLocaleTimeString("en-GB", { timeZone: "America/Argentina/Buenos_Aires" });
const isoNow = now.toISOString();
const timestamp_tz_normalizado = isoNow.replace('T', ' ').split('.')[0] + '+00';

return [{
  json: {
    query:             queryData.queryId        || 'N/A',
    pais:              envData.country          || 'Desconocido',
    entorno:           envData.entorno          || 'Desconocido',
    frecuencia:        queryData.type           || 'N/A',
    description:       queryData.description    || 'Sin descripción',
    aplicacion:        queryData.application    || 'N/A',
    tiempo:            parseFloat(((endTime - startTime) / 1000).toFixed(2)),
    peso:              parseFloat((sizeInBytes / 1024).toFixed(2)),
    filas_encontradas: realResultsCount,
    timestamp_tz:      timestamp_tz_normalizado,
    fecha_real:        arDateStr,
    hora_limpia:       arTimeStr,
    status:            !hasError, // true = Todo bien (sin errores), false = Falló (fatal o reintentos agotados)
    error_message:     errorMessage
  }
}];

// Nombre exacto del nodo anterior tal cual aparece en tu lienzo
const targetNode = 'SQL Execute2';
