// 3. Escaneo en los Metadatos del Ítem de Entrada
try {
    const inputItem = $input.first();
    // A veces n8n lo esconde fuera del json, en la raíz del item
    scanResults.rutaInputItem = inputItem?.error || "No encontrado";
} catch (e) { 
    scanResults.rutaInputItem = "Fallo al evaluar la ruta"; 
}

// 4. Escaneo vía la función interna $items()
try {
